import json
import anthropic

client = anthropic.Anthropic()


def extract_entities(text: str) -> dict:
    """
    Batch extraction task — one-shot, no dialogue, no safety concerns.
    Instruction-tuned model: directive in, JSON out.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",   # fastest / cheapest tier
        max_tokens=256,
        messages=[{
            "role": "user",
            "content": (
                f"Extract all company names, person names, and dates from the text below.\n"
                f'Return ONLY valid JSON: {{"companies": [], "people": [], "dates": []}}.\n\n'
                f"{text}"
            ),
        }],
    )
    return json.loads(response.content[0].text)


articles = [
    "On March 5, 2024, Acme Corp and Globex announced a merger. CEO Jane Doe signed the agreement.",
    "Umbrella Industries reported Q4 losses on 12 January 2025. CFO Bob Smith commented.",
]

for article in articles:
    data = extract_entities(article)
    print(data)
# {"companies": ["Acme Corp", "Globex"], "people": ["Jane Doe"], "dates": ["March 5, 2024"]}
# {"companies": ["Umbrella Industries"], "people": ["Bob Smith"], "dates": ["12 January 2025"]}
